async function verifyPayment(orderId) {
  const result = await client.get(`/payments/${orderId}`, { timeout: 3000 });
  await updateOrder(orderId, result.status);
  return result.status;
}

queue.process(async job => {
  return verifyPayment(job.orderId);
});

function sendNotices() {
  var sheet = SpreadsheetApp.getActive().getSheetByName('신청자');
  var rows = sheet.getDataRange().getValues();
  for (var i = 1; i < rows.length; i++) {
    var email = rows[i][2];
    var status = rows[i][5];
    if (status != 'sent') {
      MailApp.sendEmail(email, '안내', '교육 안내문입니다');
      sheet.getRange(i+1, 6).setValue('sent');
    }
  }
}
